def decompose_number(n):
    if n == 0:
        return ""

    str_n = str(n)
    length = len(str_n)
    components = []

    for i, digit in enumerate(str_n):
        if digit != '0':
            power = length - i - 1
            if power == 0:
                components.append(f"{digit}")
            else:
                components.append(f"{digit}*10**{power}")

    return "+".join(components)

