def find(s):
    max_combination = ""
    current_segment = ""
    last_char = ""

    i = 0
    while i < len(s):
        if s[i] == '!' or s[i] == '?':
            if s[i] == last_char:
                current_segment += s[i]
            else:
                if last_char and current_segment:
                    # Check if we have a valid combination
                    if (last_char == '!' and s[i] == '?') or (last_char == '?' and s[i] == '!'):
                        combination = current_segment + s[i]
                        j = i + 1
                        while j < len(s) and s[j] == s[i]:
                            combination += s[j]
                            j += 1
                        if len(combination) > len(max_combination):
                            max_combination = combination
                # Reset current segment
                current_segment = s[i]
            last_char = s[i]
        else:
            # Reset if we encounter a non-!/? character
            current_segment = ""
            last_char = ""
        i += 1

    return max_combination

