def transform_string(s):
    vowels = {'a', 'e', 'i', 'o', 'u'}
    special_cases = {'c', 'o', 'd', 'e'}

    def move_consonant(c):
        if c == 'c':
            return 'b'
        elif c == 'o':
            return 'n'
        elif c == 'd':
            return 'a'
        else:
            new_char = chr(((ord(c) - ord('a') + 9) % 26) + ord('a'))
            if new_char in special_cases:
                return c
            return new_char

    def move_vowel(c):
        if c == 'e':
            return 'a'
        else:
            new_char = chr(((ord(c) - ord('a') - 5) % 26) + ord('a'))
            if new_char in special_cases:
                return c
            return new_char

    result = []
    for char in s:
        if char in vowels:
            result.append(move_vowel(char))
        else:
            result.append(move_consonant(char))

    return ''.join(result)

