def is_polydivisible(n):
    s = str(n)
    for i in range(1, len(s) + 1):
        if int(s[:i]) % i != 0:
            return False
    return True

def next_polydivisible(n):
    current = n + 1
    while True:
        if is_polydivisible(current):
            return current
        current += 1
        # If the number becomes too large, we can stop (practical limit)
        if current > 10**18:  # Arbitrary large number to prevent infinite loop
            return None

