def can_become_strictly_increasing(sequence):
    def is_strictly_increasing(seq):
        return all(seq[i] < seq[i+1] for i in range(len(seq) - 1))

    # Count the number of places where the sequence is not strictly increasing
    count = 0
    index = -1
    for i in range(len(sequence) - 1):
        if sequence[i] >= sequence[i + 1]:
            count += 1
            index = i
            if count > 1:
                return False

    # If no violations, the sequence is already strictly increasing
    if count == 0:
        return True

    # If there is exactly one violation, check the two possible removals
    # Remove sequence[index] or sequence[index + 1]
    if index == 0 or index == len(sequence) - 2:
        return True
    if sequence[index - 1] < sequence[index + 1] or sequence[index] < sequence[index + 2]:
        return True

    return False

