def almost_everywhere_zero(n, k):
    n_str = str(n)
    length = len(n_str)

    # Memoization dictionary
    memo = {}

    def count(pos, tight, non_zero_count):
        if non_zero_count > k:
            return 0
        if pos == length:
            return 1 if non_zero_count == k else 0
        if (pos, tight, non_zero_count) in memo:
            return memo[(pos, tight, non_zero_count)]

        limit = int(n_str[pos]) if tight else 9
        total_count = 0

        for digit in range(0, limit + 1):
            total_count += count(pos + 1, tight and (digit == limit), non_zero_count + (digit != 0))

        memo[(pos, tight, non_zero_count)] = total_count
        return total_count

    return count(0, True, 0)

