def solve_expression(expression):
    import re

    # Split the expression into parts
    match = re.match(r"([-\d?]+)([+\-*])([-\d?]+)=([-\d?]+)", expression)
    if not match:
        return -1

    left_operand, operator, right_operand, result = match.groups()

    # Find all digits already used in the expression
    used_digits = set(re.findall(r'\d', expression))

    # Function to replace '?' with a digit and check if it forms a valid number
    def valid_number(s, digit):
        if '?' in s:
            s = s.replace('?', str(digit))
        # Check for leading zeroes
        if len(s) > 1 and s[0] == '0':
            return None
        # Convert to integer
        try:
            return int(s)
        except ValueError:
            return None

    # Try each digit from 0 to 9
    for digit in range(10):
        if str(digit) in used_digits:
            continue

        # Replace '?' with the current digit and validate
        left = valid_number(left_operand, digit)
        right = valid_number(right_operand, digit)
        res = valid_number(result, digit)

        if left is None or right is None or res is None:
            continue

        # Evaluate the expression
        if operator == '+':
            if left + right == res:
                return digit
        elif operator == '-':
            if left - right == res:
                return digit
        elif operator == '*':
            if left * right == res:
                return digit

    # If no valid digit is found
    return -1

