def count_ways(n, k):
    def find_ways(product, k, start):
        if k == 1:
            if product >= start:
                return 1
            else:
                return 0
        count = 0
        for i in range(start, product + 1):
            if product % i == 0:
                count += find_ways(product // i, k - 1, i)
        return count

    return find_ways(n, k, 1)

