def total_inc_dec(x):
    def binomial_coefficient(n, k):
        if k > n:
            return 0
        if k == 0 or k == n:
            return 1
        k = min(k, n - k)
        c = 1
        for i in range(k):
            c = c * (n - i) // (i + 1)
        return c

    if x == 0:
        return 1

    total = 0

    for n in range(1, x + 1):
        increasing = binomial_coefficient(n + 9, 9)
        decreasing = binomial_coefficient(n + 10, 10)
        total += increasing + decreasing - 10  # Subtract 10 for the double-counted numbers

    return total + 1  # Add 1 for the number 0

