    print(same_structure_as([1, [1, 1]], [2, [2, 2]]))  # True
    print(same_structure_as([1, [1, 1]], [[2, 2], 2]))  # False
    print(same_structure_as([1, [1, 1]], [[2], 2]))  # False
    print(same_structure_as([[[ ], [ ]]], [[[ ], [ ]]]))  # True
    print(same_structure_as([[[ ], [ ]]], [[1, 1]]))  # False

def largest_unrepresentable_number(numbers):
    from math import gcd
    from functools import reduce

    def gcd_list(lst):
        return reduce(gcd, lst)

    # If the GCD of all numbers is greater than 1, return -1
    if gcd_list(numbers) > 1:
        return -1

    # Sort numbers to start with the smallest
    numbers.sort()

    # Use a set to track representable numbers
    max_check = max(numbers) * max(numbers)  # A safe upper bound to check
    representable = [False] * (max_check + 1)
    representable[0] = True  # 0 is always representable (sum of zero elements)

    # Mark all representable numbers
    for i in range(max_check + 1):
        if representable[i]:
            for num in numbers:
                if i + num <= max_check:
                    representable[i + num] = True

    # Find the largest number that is not representable
    for i in range(max_check, -1, -1):
        if not representable[i]:
            return i

    return 0  # If all numbers are representable, return 0

