    index = 2
    for _ in range(q):
        r = int(data[index])
        c = int(data[index + 1])
        queries.append((r, c))
        index += 2

    # Initialize the grid state
    lava_count = [0] * (n + 1)  # lava_count[c] = number of lava cells in column c
    blocked_columns = 0  # number of columns that are completely blocked

    results = []

    for r, c in queries:
        # Toggle the cell (r, c)
        if lava_count[c] == 2:
            blocked_columns -= 1

        if r == 1:
            if lava_count[c] == 1:
                lava_count[c] -= 1
            else:
                lava_count[c] += 1
        else:  # r == 2
            if lava_count[c] == 1:
                lava_count[c] -= 1
            else:
                lava_count[c] += 1

        if lava_count[c] == 2:
            blocked_columns += 1

        # Check if the path is possible
        if blocked_columns == 0:
            results.append("Yes")
        else:
            results.append("No")

