def solve_berzerk_game():
    import sys
    input = sys.stdin.read
    data = input().split()

    n = int(data[0])
    k1 = int(data[1])
    s1 = list(map(int, data[2:2 + k1]))
    k2 = int(data[2 + k1])
    s2 = list(map(int, data[3 + k1:3 + k1 + k2]))

    # Initialize outcomes
    rick_outcome = ["Loop"] * n
    morty_outcome = ["Loop"] * n

    # Base case: if the monster is at the black hole, the player loses
    rick_outcome[0] = "Lose"
    morty_outcome[0] = "Lose"

    # Queue for BFS
    from collections import deque
    queue = deque()

    # Initialize the queue with direct win positions
    for move in s1:
        if move < n:
            morty_outcome[move] = "Win"
            queue.append((move, "Morty"))

    for move in s2:
        if move < n:
            rick_outcome[move] = "Win"
            queue.append((move, "Rick"))

    # BFS to determine outcomes
    while queue:
        pos, player = queue.popleft()

        if player == "Rick":
            # Morty is the next player
            for move in s2:
                prev_pos = (pos - move) % n
                if prev_pos == 0:
                    continue
                if morty_outcome[prev_pos] == "Loop":
                    if rick_outcome[pos] == "Lose":
                        morty_outcome[prev_pos] = "Win"
                        queue.append((prev_pos, "Morty"))
                    elif all(rick_outcome[(prev_pos - m) % n] == "Win" for m in s2):
                        morty_outcome[prev_pos] = "Lose"
                        queue.append((prev_pos, "Morty"))

        elif player == "Morty":
            # Rick is the next player
            for move in s1:
                prev_pos = (pos - move) % n
                if prev_pos == 0:
                    continue
                if rick_outcome[prev_pos] == "Loop":
                    if morty_outcome[pos] == "Lose":
                        rick_outcome[prev_pos] = "Win"
                        queue.append((prev_pos, "Rick"))
                    elif all(morty_outcome[(prev_pos - m) % n] == "Win" for m in s1):
                        rick_outcome[prev_pos] = "Lose"
                        queue.append((prev_pos, "Rick"))

    # Output results
    print(" ".join(rick_outcome[1:]))
    print(" ".join(morty_outcome[1:]))

