    alice_count = {}
    bob_count = {}

    for fish in alice_fish:
        if fish in alice_count:
            alice_count[fish] += 1
        else:
            alice_count[fish] = 1

    for fish in bob_fish:
        if fish in bob_count:
            bob_count[fish] += 1
        else:
            bob_count[fish] = 1

    # Check from the heaviest to the lightest
    for fish_type in range(k, 0, -1):
        alice_fish_count = alice_count.get(fish_type, 0)
        bob_fish_count = bob_count.get(fish_type, 0)

        if alice_fish_count > bob_fish_count:
            return "YES"

    return "NO"

