def find_lucky_permutation(n):
    if n % 2 == 1:
        return "-1"
    else:
        # Create a permutation by swapping adjacent elements
        permutation = []
        for i in range(1, n + 1, 2):
            permutation.append(i + 1)
            permutation.append(i)
        return " ".join(map(str, permutation))

